def compute_score() -> tuple[str, float]:
    """Score whether slide 4's title was updated exactly as specified.

    We expect:
      Original title: "Longitudinal Axis (2 of 3)"
      Updated title:  "Longitudinal Axis - Roll Movement (2 of 3)"

    Whitespace (including non-breaking spaces) is normalized before comparison.
    """
    import re

    def _norm(s):
        return re.sub(r"\s+", " ", (s or "")).strip()

    expected_original = "Longitudinal Axis (2 of 3)"
    expected_modified = "Longitudinal Axis - Roll Movement (2 of 3)"

    for orig_slide, mod_slide in ppt_diff.modified_slides:
        if orig_slide.slide_number == 4:
            if _norm(orig_slide.title) == _norm(expected_original):
                if _norm(mod_slide.title) == _norm(expected_modified):
                    reason = "Slide 4 title successfully changed to the exact expected text."
                    return reason, 1.0
                else:
                    reason = (
                        "Slide 4 title modification found but does not exactly match expected.\n"
                        f"Expected: '{expected_modified}'\nFound: '{mod_slide.title}'"
                    )
                    return reason, 0.0
            else:
                reason = (
                    f"Original title of slide 4 does not match expected: '{orig_slide.title}'."
                )
                return reason, 0.0
    return "No title modification found for slide 4.", 0.0
